public class MethodOverloading {
    static void printItems(String... items) {
        for (String item : items) {
            System.out.print(item + " ");
        }
        System.out.println();
    }

    public static void main(String[] args) {
        printItems("A", "B");
        printItems("One", "Two", "Three");
    }
}
